B.TS=new A.N("Face-to-face tutoring takes place in the Library (SOAR Center) with RCC tutors.\n\nOnline tutoring is provided through Upswing - live tutoring, assignment review, and study support.",null,B.G,null,null)
B.TU=new A.N("Explores interests, transferrable skills, abilities, and work values to identify career options.",null,B.G,null,null)
